import "sort"

func solve(nums []int64, k int64) int64 {
    sort.Slice(nums, func(i, j int) bool { return nums[i] < nums[j] })
    n := int64(len(nums))
    minRemoval := n - 1
    left := 0

    for right := 0; right < len(nums); right++ {
        for nums[right] > nums[left]*k {
            left++
        }
        currentWindow := int64(right - left + 1)
        if n-currentWindow < minRemoval {
            minRemoval = n - currentWindow
        }
    }
    return minRemoval
}
